const KML_B64="";
export default {
  async fetch(req, env) {
    const url = new URL(req.url);
    if (url.pathname === "/setx.kml") {
      const kml = new TextDecoder().decode(Uint8Array.from(atob(KML_B64), c => c.charCodeAt(0)));
      return new Response(kml, { headers: { "content-type": "application/vnd.google-earth.kml+xml; charset=utf-8", "cache-control": "no-store" } });
    }
    const key = url.searchParams.get("key") || (env && env.TILES_KEY) || "AIzaSyDsv6pVM0beDl0xaqNWmVkyBiUuzxRDr5c";
    const html = PAGE.replaceAll("__TILES_KEY__", key);
    return new Response(html, { headers: { "content-type": "text/html; charset=utf-8", "cache-control": "no-store" } });
  }
};

const PAGE = String.raw`<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8" />
<meta name="viewport" content="width=device-width, initial-scale=1, maximum-scale=1, user-scalable=no" />
<title>Oxley Globe — Immersive</title>
<script src="https://cesium.com/downloads/cesiumjs/releases/1.124/Build/Cesium/Cesium.js"></script>
<link href="https://cesium.com/downloads/cesiumjs/releases/1.124/Build/Cesium/Widgets/widgets.css" rel="stylesheet" />
<style>
  html, body, #cesiumContainer { width:100%; height:100%; margin:0; padding:0; overflow:hidden; background:#000; }
  #bar {
    position:absolute; top:0; left:0; right:0; z-index:10;
    display:flex; gap:8px; align-items:center; padding:8px 10px;
    background:linear-gradient(#000c,#0000); color:#e8e8e8;
    font:13px/1.2 -apple-system,Segoe UI,Roboto,sans-serif;
  }
  #bar button, #bar label {
    background:#161616; color:#eee; border:1px solid #333; border-radius:6px;
    padding:7px 11px; cursor:pointer; white-space:nowrap;
  }
  #bar button:hover, #bar label:hover { background:#222; }
  #status { margin-left:auto; opacity:.7; }
  #drop { position:absolute; inset:0; z-index:5; display:none;
    background:#0af3; border:3px dashed #0af; align-items:center; justify-content:center;
    color:#fff; font:600 20px sans-serif; }
  #drop.on { display:flex; }
  input[type=file]{ display:none; }
  .cesium-viewer-bottom{ display:none; }
</style>
</head>
<body>
<div id="bar">
  <label for="kmlFile">Load KML</label>
  <input id="kmlFile" type="file" accept=".kml,.kmz" />
  <button id="fly">Fly to pins</button>
  <button id="top">Top-down</button>
  <button id="reset">Reset view</button>
  <button id="clearRoute">Clear route</button>
  <span id="status">booting…</span>
</div>
<div id="drop">drop KML here</div>
<div id="cesiumContainer"></div>
<div id="legend" style="position:absolute;bottom:16px;left:12px;z-index:10;background:rgba(0,0,0,.78);border:1px solid #333;border-radius:8px;padding:8px 12px;font:12px/1.6 sans-serif;color:#ddd;display:none">
  <div style="font-weight:600;letter-spacing:.5px;margin-bottom:2px">STATUS</div>
  <div><span style="display:inline-block;width:9px;height:9px;border-radius:50%;background:#2ecc71;margin-right:6px;vertical-align:middle"></span>Sold</div>
  <div><span style="display:inline-block;width:9px;height:9px;border-radius:50%;background:#f5a623;margin-right:6px;vertical-align:middle"></span>Visited</div>
  <div><span style="display:inline-block;width:9px;height:9px;border-radius:50%;background:#aaa;margin-right:6px;vertical-align:middle"></span>Dead</div>
  <div><span style="display:inline-block;width:9px;height:9px;border-radius:50%;background:#0ff;margin-right:6px;vertical-align:middle"></span>Fresh lead</div>
</div>

<script>
const $ = s => document.querySelector(s);
const setStatus = t => $("#status").textContent = t;

const params = new URLSearchParams(location.search);
let GKEY = params.get("key") || "__TILES_KEY__";
if (!GKEY || GKEY.indexOf("__TILES") === 0) GKEY = prompt("Google Map Tiles API key:") || "";
let ROUTES_KEY = params.get("routesKey") || GKEY;
const ENRICH_BASE = params.get("enrichBase") || "https://oxley-enrich.moxley.workers.dev";
const NOTES_BASE = "https://oxley-beams.moxley.workers.dev";

// Status colors: status wins over fleet-size color; no status = fleet-size KML col.
const STATUS_COLORS = { sold:'#2ecc71', visited:'#f5a623', dead:'#999', lead:'#00bfff' };
let NOTECACHE = {};

async function loadNotes(){
  try { const r = await fetch(NOTES_BASE + "/notes"); if (r.ok) NOTECACHE = await r.json() || {}; } catch(e){}
}

// Extract USDOT number from the SAFER link embedded in the KML description.
function extractDot(ent){
  try {
    const raw = ent.description;
    const desc = raw ? (raw.getValue ? raw.getValue(Cesium.JulianDate.now()) : String(raw)) : "";
    const m = desc.match(/query_string=(\d+)/);
    return m ? m[1] : null;
  } catch(e){ return null; }
}

Cesium.Ion.defaultAccessToken = undefined;
Cesium.GoogleMaps.defaultApiKey = GKEY;

const viewer = new Cesium.Viewer("cesiumContainer", {
  globe: false,
  baseLayerPicker: false,
  geocoder: false,
  homeButton: false,
  sceneModePicker: false,
  navigationHelpButton: false,
  timeline: false,
  animation: false,
  fullscreenButton: true,
  vrButton: true,
  infoBox: true,
  selectionIndicator: true,
});

const cc = viewer.scene.screenSpaceCameraController;
cc.enableCollisionDetection = true;
cc.minimumZoomDistance = 1;
cc.zoomFactor = 12.0;   // boost sensitivity — default 5 feels sluggish with short beams
viewer.scene.skyAtmosphere.show = true;

const HOME = Cesium.Cartesian3.fromDegrees(-94.14, 30.10, 9000);
function reset(){
  viewer.camera.flyTo({ destination: HOME,
    orientation:{ heading:0, pitch:Cesium.Math.toRadians(-35), roll:0 }, duration:1.5 });
}

(async () => {
  try {
    setStatus("loading 3D tiles…");
    const ts = await Cesium.createGooglePhotorealistic3DTileset();
    viewer.scene.primitives.add(ts);
    setStatus("ready — orbit: L-drag · tilt: R-drag / 2-finger · zoom: scroll/pinch");
    reset();
  } catch (e) {
    setStatus("3D tiles failed — check key / Map Tiles API. " + (e.message||e));
  }
  const kmlUrl = params.get("kml") || "/setx.kml";
  if (kmlUrl) loadKml(kmlUrl);
})();

const INF = Number.POSITIVE_INFINITY;
function styleFleetDS(ds){
  ds.clustering.enabled = true;
  ds.clustering.pixelRange = 42;
  ds.clustering.minimumClusterSize = 8;
  const ents = ds.entities.values;
  let soldCount = 0, visitedCount = 0;
  for (let i=0;i<ents.length;i++){
    const ent = ents[i];
    if (!ent.position) continue;

    // Determine status from notes cache keyed by USDOT number.
    const dot = extractDot(ent);
    const noteEntry = dot ? NOTECACHE[dot] : null;
    const status = (noteEntry && noteEntry.status) ? noteEntry.status : "";

    // Status wins over fleet-size KML color; no status = use KML col.
    let col;
    if (status && STATUS_COLORS[status]){
      col = Cesium.Color.fromCssColorString(STATUS_COLORS[status]);
      if (status === "sold") soldCount++;
      if (status === "visited") visitedCount++;
    } else {
      col = Cesium.Color.CYAN;
      try { if (ent.properties && ent.properties.col) col = Cesium.Color.fromCssColorString(ent.properties.col.getValue()); } catch(e){}
    }

    const isDead = status === "dead";
    const isSold = status === "sold";
    ent.billboard = undefined;
    ent.point = new Cesium.PointGraphics({
      pixelSize: isSold ? 17 : 13,
      color: isDead ? col.withAlpha(0.35) : col,
      outlineColor: Cesium.Color.WHITE,
      outlineWidth: status ? 3 : 2,
      disableDepthTestDistance: INF
    });
    ent.label = new Cesium.LabelGraphics({
      text: ent.name,
      font: "13px sans-serif",
      fillColor: isDead ? Cesium.Color.fromCssColorString("#888") : Cesium.Color.WHITE,
      outlineColor: Cesium.Color.BLACK,
      outlineWidth: 3,
      style: Cesium.LabelStyle.FILL_AND_OUTLINE,
      pixelOffset: new Cesium.Cartesian2(0,-18),
      distanceDisplayCondition: new Cesium.DistanceDisplayCondition(0.0, 4000.0),
      disableDepthTestDistance: INF
    });

    // Prepend a status badge to the infobox description.
    if (status){
      const badge = '<div style="display:inline-block;padding:3px 12px;border-radius:12px;background:' +
        STATUS_COLORS[status] + ';color:#fff;font-size:12px;font-weight:700;text-transform:uppercase;' +
        'letter-spacing:.5px;margin-bottom:8px">' + status + '</div><br>';
      try {
        const raw = ent.description;
        const cur = raw ? (raw.getValue ? raw.getValue(Cesium.JulianDate.now()) : String(raw)) : "";
        ent.description = badge + cur;
      } catch(e){}
    }
  }
  // Show legend and update status bar with a sold/visited tally.
  const leg = document.getElementById("legend");
  if (leg) leg.style.display = "block";
  if (soldCount || visitedCount)
    setStatus(ds.entities.values.length + " pins · " + soldCount + " sold · " + visitedCount + " visited");
}

// Merge cached Places enrichment (photo/hours/phone/rating) into Tier-1 pin cards.
function applyEnrichment(ds){
  fetch(ENRICH_BASE + "/enriched.json").then(r => r.ok ? r.json() : []).then(recs => {
    if (!recs || !recs.length) return;
    const norm = s => (s || "").toUpperCase().replace(/&AMP;/g, "&").replace(/[^A-Z0-9]/g, "");
    const R = recs.map(x => ({ rec: x, key: norm(x.n) })).filter(x => x.key.length >= 5);
    const ents = ds.entities.values;
    let n = 0;
    for (let i = 0; i < ents.length; i++){
      const ent = ents[i];
      if (!ent.name) continue;
      const en = norm(ent.name);
      let found = null;
      for (let j = 0; j < R.length; j++){
        if (en.indexOf(R[j].key) !== -1 || R[j].key.indexOf(en) !== -1){ found = R[j].rec; break; }
      }
      if (!found) continue;
      const parts = [];
      parts.push('<div style="font:13px/1.4 sans-serif;color:#eee">');
      if (found.photo) parts.push('<img src="' + ENRICH_BASE + found.photo + '" style="width:100%;max-width:340px;border-radius:8px;margin:6px 0" />');
      if (found.rating) parts.push('<div>&#9733; ' + found.rating + (found.ratingCount ? ' (' + found.ratingCount + ')' : '') + '</div>');
      if (found.phone) parts.push('<div>&#128222; <a style="color:#4ab3ff" href="tel:' + found.phone + '">' + found.phone + '</a></div>');
      if (found.website) parts.push('<div><a style="color:#4ab3ff" href="' + found.website + '" target="_blank" rel="noopener">website</a></div>');
      if (found.hours && found.hours.length){
        parts.push('<div style="margin-top:5px;opacity:.85">');
        for (let h = 0; h < found.hours.length; h++) parts.push('<div>' + found.hours[h] + '</div>');
        parts.push('</div>');
      }
      parts.push('</div>');
      const cur = ent.description ? (ent.description.getValue ? ent.description.getValue(viewer.clock.currentTime) : ent.description) : "";
      ent.description = parts.join("") + (cur || "");
      n++;
    }
    if (n) setStatus(n + " Tier-1 pin" + (n === 1 ? "" : "s") + " enriched · " + ds.entities.values.length + " pins total");
  }).catch(() => {});
}

let currentDS = null;
async function loadKml(source){
  try {
    _pinLoading = true;
    setStatus("loading pins…");
    if (currentDS) viewer.dataSources.remove(currentDS, true);
    await loadNotes();   // fetch status notes before styling so colors are ready
    const ds = await Cesium.KmlDataSource.load(source, {
      camera: viewer.camera, canvas: viewer.canvas, clampToGround: false
    });
    currentDS = await viewer.dataSources.add(ds);
    styleFleetDS(ds);
    applyEnrichment(ds);
    await viewer.flyTo(ds);
    if (!Object.keys(NOTECACHE).length)
      setStatus(ds.entities.values.length + " pins — tap a pin for details");
  } catch(e){ setStatus("KML failed: " + (e.message||e)); }
  finally { _pinLoading = false; }
}

$("#kmlFile").addEventListener("change", e => { if(e.target.files[0]) loadKml(e.target.files[0]); });
$("#fly").addEventListener("click", () => currentDS && viewer.flyTo(currentDS));
$("#reset").addEventListener("click", reset);
$("#top").addEventListener("click", () => {
  const c = viewer.camera.positionCartographic;
  viewer.camera.flyTo({
    destination: Cesium.Cartesian3.fromRadians(c.longitude, c.latitude, Math.max(c.height,4000)),
    orientation:{ heading:0, pitch:Cesium.Math.toRadians(-90), roll:0 }, duration:1 });
});

const drop = $("#drop"), body = document.body;
["dragenter","dragover"].forEach(ev => body.addEventListener(ev, e=>{e.preventDefault(); drop.classList.add("on");}));
["dragleave","drop"].forEach(ev => body.addEventListener(ev, e=>{e.preventDefault(); if(ev==="drop"||e.target===drop) drop.classList.remove("on");}));
body.addEventListener("drop", e => { const f=e.dataTransfer.files[0]; if(f) loadKml(f); });

// ---- In-app routing: tap a pin -> draw driving route on the globe ----
let routeEntity = null;
function clearRoute(){
  if (routeEntity){ viewer.entities.remove(routeEntity); routeEntity = null; }
}
$("#clearRoute").addEventListener("click", () => { clearRoute(); setStatus("route cleared"); });

// Google encoded-polyline decoder -> [ [lat,lng], ... ]
function decodePolyline(str){
  let index = 0, lat = 0, lng = 0;
  const coords = [];
  while (index < str.length){
    let b, shift = 0, result = 0;
    do { b = str.charCodeAt(index++) - 63; result |= (b & 0x1f) << shift; shift += 5; } while (b >= 0x20);
    lat += (result & 1) ? ~(result >> 1) : (result >> 1);
    shift = 0; result = 0;
    do { b = str.charCodeAt(index++) - 63; result |= (b & 0x1f) << shift; shift += 5; } while (b >= 0x20);
    lng += (result & 1) ? ~(result >> 1) : (result >> 1);
    coords.push([lat * 1e-5, lng * 1e-5]);
  }
  return coords;
}

function fmtDuration(d){
  const secs = parseInt(d, 10) || 0;
  const mins = Math.round(secs / 60);
  if (mins < 60) return mins + " min";
  return Math.floor(mins / 60) + "h " + (mins % 60) + "m";
}

function routeToEntity(ent){
  if (!ent || !ent.position) return;
  const pos = ent.position.getValue(viewer.clock.currentTime);
  if (!pos) return;
  const carto = Cesium.Cartographic.fromCartesian(pos);
  const destLat = Cesium.Math.toDegrees(carto.latitude);
  const destLng = Cesium.Math.toDegrees(carto.longitude);
  const name = ent.name || "destination";
  if (!navigator.geolocation){ setStatus("no geolocation on this device"); return; }
  setStatus("locating you…");
  navigator.geolocation.getCurrentPosition(async (geo) => {
    const oLat = geo.coords.latitude, oLng = geo.coords.longitude;
    setStatus("routing to " + name + "…");
    try {
      const resp = await fetch("https://routes.googleapis.com/directions/v2:computeRoutes", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "X-Goog-Api-Key": ROUTES_KEY,
          "X-Goog-FieldMask": "routes.polyline.encodedPolyline,routes.distanceMeters,routes.duration"
        },
        body: JSON.stringify({
          origin: { location: { latLng: { latitude: oLat, longitude: oLng } } },
          destination: { location: { latLng: { latitude: destLat, longitude: destLng } } },
          travelMode: "DRIVE"
        })
      });
      if (!resp.ok){
        const detail = await resp.text().catch(() => "");
        console.warn("Routes API " + resp.status, detail);
        setStatus("route error " + resp.status + (resp.status === 403 ? " — add Routes API to the key" : ""));
        return;
      }
      const data = await resp.json();
      const route = data.routes && data.routes[0];
      if (!route || !route.polyline || !route.polyline.encodedPolyline){ setStatus("no route found to " + name); return; }
      const pts = decodePolyline(route.polyline.encodedPolyline);
      const flat = [];
      for (let i = 0; i < pts.length; i++){ flat.push(pts[i][1], pts[i][0]); }
      clearRoute();
      routeEntity = viewer.entities.add({
        polyline: {
          positions: Cesium.Cartesian3.fromDegreesArray(flat),
          width: 6,
          clampToGround: true,
          material: new Cesium.PolylineOutlineMaterialProperty({ color: Cesium.Color.CYAN, outlineColor: Cesium.Color.BLACK, outlineWidth: 2 })
        }
      });
      const miles = (route.distanceMeters / 1609.34);
      setStatus(name + " — " + miles.toFixed(1) + " mi · " + fmtDuration(route.duration) + " drive");
    } catch (err) {
      setStatus("route failed: " + (err.message || err));
    }
  }, (err) => {
    setStatus("location unavailable: " + err.message);
  }, { enableHighAccuracy: true, timeout: 15000, maximumAge: 60000 });
}

// Only route on explicit user tap — not during programmatic flyTo/load.
let _pinLoading = false;
viewer.selectedEntityChanged.addEventListener((ent) => {
  if (!_pinLoading && ent && ent.position) routeToEntity(ent);
});
</script>
</body>
</html>`;
